"use strict";(self.webpackChunkmy_blog=self.webpackChunkmy_blog||[]).push([[14238],{66262:(n,s)=>{s.A=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}},5256:(n,s,a)=>{a.r(s),a.d(s,{comp:()=>p,data:()=>t});var e=a(20641);const i=a.p+"assets/img/CgqCHl_ArGSAfxA6AAHyWL4Af1o908.4bbf8f46.png",l={},p=(0,a(66262).A)(l,[["render",function(n,s){return(0,e.uX)(),(0,e.CE)("div",null,s[0]||(s[0]=[(0,e.Fv)('<h1 id="_36-负载均衡-公平公正物尽其用的负载均衡策略-这里都有-下" tabindex="-1"><a class="header-anchor" href="#_36-负载均衡-公平公正物尽其用的负载均衡策略-这里都有-下"><span>36 负载均衡：公平公正物尽其用的负载均衡策略，这里都有（下）</span></a></h1><p>在上一课时我们了解了 LoadBalance 接口定义以及 AbstractLoadBalance 抽象类的内容，还详细介绍了 ConsistentHashLoadBalance 以及 RandomLoadBalance 这两个实现类的核心原理和大致实现。本课时我们将继续介绍 LoadBalance 的剩余三个实现。</p><h3 id="leastactiveloadbalance" tabindex="-1"><a class="header-anchor" href="#leastactiveloadbalance"><span>LeastActiveLoadBalance</span></a></h3><p>LeastActiveLoadBalance 使用的是<strong>最小活跃数负载均衡算法</strong>。它认为当前活跃请求数越小的 Provider 节点，剩余的处理能力越多，处理请求的效率也就越高，那么该 Provider 在单位时间内就可以处理更多的请求，所以我们应该优先将请求分配给该 Provider 节点。</p><p>LeastActiveLoadBalance 需要配合 ActiveLimitFilter 使用，ActiveLimitFilter 会记录每个接口方法的活跃请求数，在 LeastActiveLoadBalance 进行负载均衡时，只会从活跃请求数最少的 Invoker 集合里挑选 Invoker。</p><p>在 LeastActiveLoadBalance 的实现中，首先会选出所有活跃请求数最小的 Invoker 对象，之后的逻辑与 RandomLoadBalance 完全一样，即按照这些 Invoker 对象的权重挑选最终的 Invoker 对象。下面是 LeastActiveLoadBalance.doSelect() 方法的具体实现：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>protected &lt;T&gt; Invoker&lt;T&gt; doSelect(List&lt;Invoker&lt;T&gt;&gt; invokers, URL url, Invocation invocation) {</span></span>\n<span class="line"><span>    // 初始化Invoker数量</span></span>\n<span class="line"><span>    int length = invokers.size();</span></span>\n<span class="line"><span>    // 记录最小的活跃请求数</span></span>\n<span class="line"><span>    int leastActive = -1;</span></span>\n<span class="line"><span>    // 记录活跃请求数最小的Invoker集合的个数</span></span>\n<span class="line"><span>    int leastCount = 0;</span></span>\n<span class="line"><span>    // 记录活跃请求数最小的Invoker在invokers数组中的下标位置 </span></span>\n<span class="line"><span>    int[] leastIndexes = new int[length];</span></span>\n<span class="line"><span>    // 记录活跃请求数最小的Invoker集合中，每个Invoker的权重值</span></span>\n<span class="line"><span>    int[] weights = new int[length];</span></span>\n<span class="line"><span>    // 记录活跃请求数最小的Invoker集合中，所有Invoker的权重值之和</span></span>\n<span class="line"><span>    int totalWeight = 0;</span></span>\n<span class="line"><span>    // 记录活跃请求数最小的Invoker集合中，第一个Invoker的权重值</span></span>\n<span class="line"><span>    int firstWeight = 0;</span></span>\n<span class="line"><span>    // 活跃请求数最小的集合中，所有Invoker的权重值是否相同</span></span>\n<span class="line"><span>    boolean sameWeight = true;</span></span>\n<span class="line"><span>    for (int i = 0; i &lt; length; i++) { // 遍历所有Invoker，获取活跃请求数最小的Invoker集合</span></span>\n<span class="line"><span>        Invoker&lt;T&gt; invoker = invokers.get(i);</span></span>\n<span class="line"><span>        // 获取该Invoker的活跃请求数</span></span>\n<span class="line"><span>        int active = RpcStatus.getStatus(invoker.getUrl(), invocation.getMethodName()).getActive();</span></span>\n<span class="line"><span>        // 获取该Invoker的权重</span></span>\n<span class="line"><span>        int afterWarmup = getWeight(invoker, invocation);</span></span>\n<span class="line"><span>        weights[i] = afterWarmup;</span></span>\n<span class="line"><span>        // 比较活跃请求数</span></span>\n<span class="line"><span>        if (leastActive == -1 || active &lt; leastActive) {</span></span>\n<span class="line"><span>            // 当前的Invoker是第一个活跃请求数最小的Invoker，则记录如下信息</span></span>\n<span class="line"><span>            leastActive = active; // 重新记录最小的活跃请求数</span></span>\n<span class="line"><span>            leastCount = 1; // 重新记录活跃请求数最小的Invoker集合个数</span></span>\n<span class="line"><span>            leastIndexes[0] = i; // 重新记录Invoker</span></span>\n<span class="line"><span>            totalWeight = afterWarmup; // 重新记录总权重值</span></span>\n<span class="line"><span>            firstWeight = afterWarmup; // 该Invoker作为第一个Invoker，记录其权重值</span></span>\n<span class="line"><span>            sameWeight = true; // 重新记录是否权重值相等</span></span>\n<span class="line"><span>        } else if (active == leastActive) { </span></span>\n<span class="line"><span>            // 当前Invoker属于活跃请求数最小的Invoker集合</span></span>\n<span class="line"><span>            leastIndexes[leastCount++] = i; // 记录该Invoker的下标</span></span>\n<span class="line"><span>            totalWeight += afterWarmup; // 更新总权重</span></span>\n<span class="line"><span>            if (sameWeight &amp;&amp; afterWarmup != firstWeight) {</span></span>\n<span class="line"><span>                sameWeight = false; // 更新权重值是否相等</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 如果只有一个活跃请求数最小的Invoker对象，直接返回即可</span></span>\n<span class="line"><span>    if (leastCount == 1) {</span></span>\n<span class="line"><span>        return invokers.get(leastIndexes[0]);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 下面按照RandomLoadBalance的逻辑，从活跃请求数最小的Invoker集合中，随机选择一个Invoker对象返回</span></span>\n<span class="line"><span>    if (!sameWeight &amp;&amp; totalWeight &gt; 0) {</span></span>\n<span class="line"><span>        int offsetWeight = ThreadLocalRandom.current().nextInt(totalWeight);</span></span>\n<span class="line"><span>        for (int i = 0; i &lt; leastCount; i++) {</span></span>\n<span class="line"><span>            int leastIndex = leastIndexes[i];</span></span>\n<span class="line"><span>            offsetWeight -= weights[leastIndex];</span></span>\n<span class="line"><span>            if (offsetWeight &lt; 0) {</span></span>\n<span class="line"><span>                return invokers.get(leastIndex);</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    return invokers.get(leastIndexes[ThreadLocalRandom.current().nextInt(leastCount)]);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>ActiveLimitFilter 以及底层的 RpcStatus 记录活跃请求数的具体原理，在前面的[第 30 课时]中我们已经详细分析过了，这里不再重复，如果有不清楚的地方，你可以回顾之前课时相关的内容。</p><h3 id="roundrobinloadbalance" tabindex="-1"><a class="header-anchor" href="#roundrobinloadbalance"><span>RoundRobinLoadBalance</span></a></h3><p>RoundRobinLoadBalance 实现的是<strong>加权轮询负载均衡算法</strong>。</p><p>轮询指的是将请求轮流分配给每个 Provider。例如，有 A、B、C 三个 Provider 节点，按照普通轮询的方式，我们会将第一个请求分配给 Provider A，将第二个请求分配给 Provider B，第三个请求分配给 Provider C，第四个请求再次分配给 Provider A……如此循环往复。</p><p><strong>轮询是一种无状态负载均衡算法，实现简单，适用于集群中所有 Provider 节点性能相近的场景。</strong> 但现实情况中就很难保证这一点了，因为很容易出现集群中性能最好和最差的 Provider 节点处理同样流量的情况，这就可能导致性能差的 Provider 节点各方面资源非常紧张，甚至无法及时响应了，但是性能好的 Provider 节点的各方面资源使用还较为空闲。这时我们可以通过加权轮询的方式，降低分配到性能较差的 Provider 节点的流量。</p><p>加权之后，分配给每个 Provider 节点的流量比会接近或等于它们的权重比。例如，Provider 节点 A、B、C 权重比为 5:1:1，那么在 7 次请求中，节点 A 将收到 5 次请求，节点 B 会收到 1 次请求，节点 C 则会收到 1 次请求。</p><p><strong>在 Dubbo 2.6.4 版本及之前，RoundRobinLoadBalance 的实现存在一些问题，例如，选择 Invoker 的性能问题、负载均衡时不够平滑等。在 Dubbo 2.6.5 版本之后，这些问题都得到了修复</strong>，所以这里我们就来介绍最新的 RoundRobinLoadBalance 实现。</p><p>每个 Provider 节点有两个权重：一个权重是配置的 weight，该值在负载均衡的过程中不会变化；另一个权重是 currentWeight，该值会在负载均衡的过程中动态调整，初始值为 0。</p><p>当有新的请求进来时，RoundRobinLoadBalance 会遍历 Invoker 列表，并用对应的 currentWeight 加上其配置的权重。遍历完成后，再找到最大的 currentWeight，将其减去权重总和，然后返回相应的 Invoker 对象。</p><p>下面我们通过一个示例说明 RoundRobinLoadBalance 的执行流程，这里我们依旧假设 A、B、C 三个节点的权重比例为 5:1:1。</p><figure><img src="'+i+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol><li>处理第一个请求，currentWeight 数组中的权重与配置的 weight 相加，即从 [0, 0, 0] 变为 [5, 1, 1]。接下来，从中选择权重最大的 Invoker 作为结果，即节点 A。最后，将节点 A 的 currentWeight 值减去 totalWeight 值，最终得到 currentWeight 数组为 [-2, 1, 1]。</li><li>处理第二个请求，currentWeight 数组中的权重与配置的 weight 相加，即从 [-2, 1, 1] 变为 [3, 2, 2]。接下来，从中选择权重最大的 Invoker 作为结果，即节点 A。最后，将节点 A 的 currentWeight 值减去 totalWeight 值，最终得到 currentWeight 数组为 [-4, 2, 2]。</li><li>处理第三个请求，currentWeight 数组中的权重与配置的 weight 相加，即从 [-4, 2, 2] 变为 [1, 3, 3]。接下来，从中选择权重最大的 Invoker 作为结果，即节点 B。最后，将节点 B 的 currentWeight 值减去 totalWeight 值，最终得到 currentWeight 数组为 [1, -4, 3]。</li><li>处理第四个请求，currentWeight 数组中的权重与配置的 weight 相加，即从 [1, -4, 3] 变为 [6, -3, 4]。接下来，从中选择权重最大的 Invoker 作为结果，即节点 A。最后，将节点 A 的 currentWeight 值减去 totalWeight 值，最终得到 currentWeight 数组为 [-1, -3, 4]。</li><li>处理第五个请求，currentWeight 数组中的权重与配置的 weight 相加，即从 [-1, -3, 4] 变为 [4, -2, 5]。接下来，从中选择权重最大的 Invoker 作为结果，即节点 C。最后，将节点 C 的 currentWeight 值减去 totalWeight 值，最终得到 currentWeight 数组为 [4, -2, -2]。</li><li>处理第六个请求，currentWeight 数组中的权重与配置的 weight 相加，即从 [4, -2, -2] 变为 [9, -1, -1]。接下来，从中选择权重最大的 Invoker 作为结果，即节点 A。最后，将节点 A 的 currentWeight 值减去 totalWeight 值，最终得到 currentWeight 数组为 [2, -1, -1]。</li><li>处理第七个请求，currentWeight 数组中的权重与配置的 weight 相加，即从 [2, -1, -1] 变为 [7, 0, 0]。接下来，从中选择权重最大的 Invoker 作为结果，即节点 A。最后，将节点 A 的 currentWeight 值减去 totalWeight 值，最终得到 currentWeight 数组为 [0, 0, 0]。</li></ol><p>到此为止，一个轮询的周期就结束了。</p><p>而在 Dubbo 2.6.4 版本中，上面示例的一次轮询结果是 [A, A, A, A, A, B, C]，也就是说前 5 个请求会全部都落到 A 这个节点上。这将会使节点 A 在短时间内接收大量的请求，压力陡增，而节点 B 和节点 C 此时没有收到任何请求，处于完全空闲的状态，这种“瞬间分配不平衡”的情况也就是前面提到的“不平滑问题”。</p><p>在 RoundRobinLoadBalance 中，我们<strong>为每个 Invoker 对象创建了一个对应的 WeightedRoundRobin 对象</strong>，用来记录配置的权重（weight 字段）以及随每次负载均衡算法执行变化的 current 权重（current 字段）。</p><p>了解了 WeightedRoundRobin 这个内部类后，我们再来看 RoundRobinLoadBalance.doSelect() 方法的具体实现：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>protected &lt;T&gt; Invoker&lt;T&gt; doSelect(List&lt;Invoker&lt;T&gt;&gt; invokers, URL url, Invocation invocation) {</span></span>\n<span class="line"><span>    String key = invokers.get(0).getUrl().getServiceKey() + &quot;.&quot; + invocation.getMethodName();</span></span>\n<span class="line"><span>    // 获取整个Invoker列表对应的WeightedRoundRobin映射表，如果为空，则创建一个新的WeightedRoundRobin映射表</span></span>\n<span class="line"><span>    ConcurrentMap&lt;String, WeightedRoundRobin&gt; map = methodWeightMap.computeIfAbsent(key, k -&gt; new ConcurrentHashMap&lt;&gt;());</span></span>\n<span class="line"><span>    int totalWeight = 0;</span></span>\n<span class="line"><span>    long maxCurrent = Long.MIN_VALUE;</span></span>\n<span class="line"><span>    long now = System.currentTimeMillis(); // 获取当前时间</span></span>\n<span class="line"><span>    Invoker&lt;T&gt; selectedInvoker = null;</span></span>\n<span class="line"><span>    WeightedRoundRobin selectedWRR = null;</span></span>\n<span class="line"><span>    for (Invoker&lt;T&gt; invoker : invokers) {</span></span>\n<span class="line"><span>        String identifyString = invoker.getUrl().toIdentityString();</span></span>\n<span class="line"><span>        int weight = getWeight(invoker, invocation);</span></span>\n<span class="line"><span>        // 检测当前Invoker是否有相应的WeightedRoundRobin对象，没有则进行创建</span></span>\n<span class="line"><span>        WeightedRoundRobin weightedRoundRobin = map.computeIfAbsent(identifyString, k -&gt; {</span></span>\n<span class="line"><span>            WeightedRoundRobin wrr = new WeightedRoundRobin();</span></span>\n<span class="line"><span>            wrr.setWeight(weight);</span></span>\n<span class="line"><span>            return wrr;</span></span>\n<span class="line"><span>        });</span></span>\n<span class="line"><span>        // 检测Invoker权重是否发生了变化，若发生变化，则更新WeightedRoundRobin的weight字段</span></span>\n<span class="line"><span>        if (weight != weightedRoundRobin.getWeight()) {</span></span>\n<span class="line"><span>            weightedRoundRobin.setWeight(weight);</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        // 让currentWeight加上配置的Weight</span></span>\n<span class="line"><span>        long cur = weightedRoundRobin.increaseCurrent();</span></span>\n<span class="line"><span>        //  设置lastUpdate字段</span></span>\n<span class="line"><span>        weightedRoundRobin.setLastUpdate(now);</span></span>\n<span class="line"><span>        // 寻找具有最大currentWeight的Invoker，以及Invoker对应的WeightedRoundRobin</span></span>\n<span class="line"><span>        if (cur &gt; maxCurrent) {</span></span>\n<span class="line"><span>            maxCurrent = cur;</span></span>\n<span class="line"><span>            selectedInvoker = invoker;</span></span>\n<span class="line"><span>            selectedWRR = weightedRoundRobin;</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        totalWeight += weight; // 计算权重总和</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    if (invokers.size() != map.size()) {</span></span>\n<span class="line"><span>        map.entrySet().removeIf(item -&gt; now - item.getValue().getLastUpdate() &gt; RECYCLE_PERIOD);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    if (selectedInvoker != null) {</span></span>\n<span class="line"><span>        // 用currentWeight减去totalWeight</span></span>\n<span class="line"><span>        selectedWRR.sel(totalWeight);</span></span>\n<span class="line"><span>        // 返回选中的Invoker对象</span></span>\n<span class="line"><span>        return selectedInvoker;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    return invokers.get(0);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="shortestresponseloadbalance" tabindex="-1"><a class="header-anchor" href="#shortestresponseloadbalance"><span>ShortestResponseLoadBalance</span></a></h3><p>ShortestResponseLoadBalance 是<strong>Dubbo 2.7 版本之后新增加的一个 LoadBalance 实现类</strong>。它实现了<strong>最短响应时间的负载均衡算法</strong>，也就是从多个 Provider 节点中选出调用成功的且响应时间最短的 Provider 节点，不过满足该条件的 Provider 节点可能有多个，所以还要再使用随机算法进行一次选择，得到最终要调用的 Provider 节点。</p><p>了解了 ShortestResponseLoadBalance 的核心原理之后，我们一起来看 ShortestResponseLoadBalance.doSelect() 方法的核心实现，如下所示：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>protected &lt;T&gt; Invoker&lt;T&gt; doSelect(List&lt;Invoker&lt;T&gt;&gt; invokers, URL url, Invocation invocation) {</span></span>\n<span class="line"><span>    // 记录Invoker集合的数量</span></span>\n<span class="line"><span>    int length = invokers.size();</span></span>\n<span class="line"><span>    // 用于记录所有Invoker集合中最短响应时间</span></span>\n<span class="line"><span>    long shortestResponse = Long.MAX_VALUE;</span></span>\n<span class="line"><span>    // 具有相同最短响应时间的Invoker个数</span></span>\n<span class="line"><span>    int shortestCount = 0;</span></span>\n<span class="line"><span>    // 存放所有最短响应时间的Invoker的下标</span></span>\n<span class="line"><span>    int[] shortestIndexes = new int[length];</span></span>\n<span class="line"><span>    // 存储每个Invoker的权重</span></span>\n<span class="line"><span>    int[] weights = new int[length];</span></span>\n<span class="line"><span>    // 存储权重总和</span></span>\n<span class="line"><span>    int totalWeight = 0;</span></span>\n<span class="line"><span>    // 记录第一个Invoker对象的权重</span></span>\n<span class="line"><span>    int firstWeight = 0;</span></span>\n<span class="line"><span>    // 最短响应时间Invoker集合中的Invoker权重是否相同</span></span>\n<span class="line"><span>    boolean sameWeight = true;</span></span>\n<span class="line"><span>    for (int i = 0; i &lt; length; i++) {</span></span>\n<span class="line"><span>        Invoker&lt;T&gt; invoker = invokers.get(i);</span></span>\n<span class="line"><span>        RpcStatus rpcStatus = RpcStatus.getStatus(invoker.getUrl(), invocation.getMethodName());</span></span>\n<span class="line"><span>        // 获取调用成功的平均时间，具体计算方式是：调用成功的请求数总数对应的总耗时 / 调用成功的请求数总数 = 成功调用的平均时间</span></span>\n<span class="line"><span>        // RpcStatus 的内容在前面课时已经介绍过了，这里不再重复</span></span>\n<span class="line"><span>        long succeededAverageElapsed = rpcStatus.getSucceededAverageElapsed();</span></span>\n<span class="line"><span>        // 获取的是该Provider当前的活跃请求数，也就是当前正在处理的请求数</span></span>\n<span class="line"><span>        int active = rpcStatus.getActive();</span></span>\n<span class="line"><span>        // 计算一个处理新请求的预估值，也就是如果当前请求发给这个Provider，大概耗时多久处理完成</span></span>\n<span class="line"><span>        long estimateResponse = succeededAverageElapsed * active;</span></span>\n<span class="line"><span>        // 计算该Invoker的权重（主要是处理预热）</span></span>\n<span class="line"><span>        int afterWarmup = getWeight(invoker, invocation);</span></span>\n<span class="line"><span>        weights[i] = afterWarmup;</span></span>\n<span class="line"><span>        if (estimateResponse &lt; shortestResponse) { </span></span>\n<span class="line"><span>            // 第一次找到Invoker集合中最短响应耗时的Invoker对象，记录其相关信息</span></span>\n<span class="line"><span>            shortestResponse = estimateResponse;</span></span>\n<span class="line"><span>            shortestCount = 1;</span></span>\n<span class="line"><span>            shortestIndexes[0] = i;</span></span>\n<span class="line"><span>            totalWeight = afterWarmup;</span></span>\n<span class="line"><span>            firstWeight = afterWarmup;</span></span>\n<span class="line"><span>            sameWeight = true;</span></span>\n<span class="line"><span>        } else if (estimateResponse == shortestResponse) {</span></span>\n<span class="line"><span>            // 出现多个耗时最短的Invoker对象</span></span>\n<span class="line"><span>            shortestIndexes[shortestCount++] = i;</span></span>\n<span class="line"><span>            totalWeight += afterWarmup;</span></span>\n<span class="line"><span>            if (sameWeight &amp;&amp; i &gt; 0</span></span>\n<span class="line"><span>                    &amp;&amp; afterWarmup != firstWeight) {</span></span>\n<span class="line"><span>                sameWeight = false;</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    if (shortestCount == 1) {</span></span>\n<span class="line"><span>        return invokers.get(shortestIndexes[0]);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 如果耗时最短的所有Invoker对象的权重不相同，则通过加权随机负载均衡的方式选择一个Invoker返回</span></span>\n<span class="line"><span>    if (!sameWeight &amp;&amp; totalWeight &gt; 0) {</span></span>\n<span class="line"><span>        int offsetWeight = ThreadLocalRandom.current().nextInt(totalWeight);</span></span>\n<span class="line"><span>        for (int i = 0; i &lt; shortestCount; i++) {</span></span>\n<span class="line"><span>            int shortestIndex = shortestIndexes[i];</span></span>\n<span class="line"><span>            offsetWeight -= weights[shortestIndex];</span></span>\n<span class="line"><span>            if (offsetWeight &lt; 0) {</span></span>\n<span class="line"><span>                return invokers.get(shortestIndex);</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 如果耗时最短的所有Invoker对象的权重相同，则随机返回一个</span></span>\n<span class="line"><span>    return invokers.get(shortestIndexes[ThreadLocalRandom.current().nextInt(shortestCount)]);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h3><p>今天我们紧接上一课时介绍了 LoadBalance 接口的剩余三个实现。</p><p>我们首先介绍了 LeastActiveLoadBalance 实现，它使用最小活跃数负载均衡算法，选择当前请求最少的 Provider 节点处理最新的请求；接下来介绍了 RoundRobinLoadBalance 实现，它使用加权轮询负载均衡算法，弥补了单纯的轮询负载均衡算法导致的问题，同时随着 Dubbo 版本的升级，也将其自身不够平滑的问题优化掉了；最后介绍了 ShortestResponseLoadBalance 实现，它会从响应时间最短的 Provider 节点中选择一个 Provider 节点来处理新请求。</p>',31)]))}]]),t=JSON.parse('{"path":"/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98/36%20%20%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%EF%BC%9A%E5%85%AC%E5%B9%B3%E5%85%AC%E6%AD%A3%E7%89%A9%E5%B0%BD%E5%85%B6%E7%94%A8%E7%9A%84%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%E7%AD%96%E7%95%A5%EF%BC%8C%E8%BF%99%E9%87%8C%E9%83%BD%E6%9C%89%EF%BC%88%E4%B8%8B%EF%BC%89.html","title":"36  负载均衡：公平公正物尽其用的负载均衡策略，这里都有（下）","lang":"zh-CN","frontmatter":{"description":"36 负载均衡：公平公正物尽其用的负载均衡策略，这里都有（下） 在上一课时我们了解了 LoadBalance 接口定义以及 AbstractLoadBalance 抽象类的内容，还详细介绍了 ConsistentHashLoadBalance 以及 RandomLoadBalance 这两个实现类的核心原理和大致实现。本课时我们将继续介绍 LoadBa...","head":[["meta",{"property":"og:url","content":"https://chenmingxing1012.github.io/blog/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98/36%20%20%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%EF%BC%9A%E5%85%AC%E5%B9%B3%E5%85%AC%E6%AD%A3%E7%89%A9%E5%B0%BD%E5%85%B6%E7%94%A8%E7%9A%84%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%E7%AD%96%E7%95%A5%EF%BC%8C%E8%BF%99%E9%87%8C%E9%83%BD%E6%9C%89%EF%BC%88%E4%B8%8B%EF%BC%89.html"}],["meta",{"property":"og:site_name","content":"凡人修码传"}],["meta",{"property":"og:title","content":"36  负载均衡：公平公正物尽其用的负载均衡策略，这里都有（下）"}],["meta",{"property":"og:description","content":"36 负载均衡：公平公正物尽其用的负载均衡策略，这里都有（下） 在上一课时我们了解了 LoadBalance 接口定义以及 AbstractLoadBalance 抽象类的内容，还详细介绍了 ConsistentHashLoadBalance 以及 RandomLoadBalance 这两个实现类的核心原理和大致实现。本课时我们将继续介绍 LoadBa..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-06-07T05:33:45.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-07T05:33:45.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"36  负载均衡：公平公正物尽其用的负载均衡策略，这里都有（下）\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-06-07T05:33:45.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"韩跑跑\\",\\"url\\":\\"https://chenmingxing1012.github.io/blog/\\"}]}"]]},"headers":[{"level":3,"title":"LeastActiveLoadBalance","slug":"leastactiveloadbalance","link":"#leastactiveloadbalance","children":[]},{"level":3,"title":"RoundRobinLoadBalance","slug":"roundrobinloadbalance","link":"#roundrobinloadbalance","children":[]},{"level":3,"title":"ShortestResponseLoadBalance","slug":"shortestresponseloadbalance","link":"#shortestresponseloadbalance","children":[]},{"level":3,"title":"总结","slug":"总结","link":"#总结","children":[]}],"git":{"createdTime":1780673609000,"updatedTime":1780810425000,"contributors":[{"name":"chenmingxing","email":"1060303243@qq.com","commits":1}]},"readingTime":{"minutes":11.07,"words":3321},"filePathRelative":"column/Dubbo源码解读与实战/36  负载均衡：公平公正物尽其用的负载均衡策略，这里都有（下）.md","localizedDate":"2026年6月5日","excerpt":"\\n<p>在上一课时我们了解了 LoadBalance 接口定义以及 AbstractLoadBalance 抽象类的内容，还详细介绍了 ConsistentHashLoadBalance 以及 RandomLoadBalance 这两个实现类的核心原理和大致实现。本课时我们将继续介绍 LoadBalance 的剩余三个实现。</p>\\n<h3>LeastActiveLoadBalance</h3>\\n<p>LeastActiveLoadBalance 使用的是<strong>最小活跃数负载均衡算法</strong>。它认为当前活跃请求数越小的 Provider 节点，剩余的处理能力越多，处理请求的效率也就越高，那么该 Provider 在单位时间内就可以处理更多的请求，所以我们应该优先将请求分配给该 Provider 节点。</p>","autoDesc":true}')}}]);